<template>
  <div>
    <el-breadcrumb separator="/" style="padding-left: 10px;padding-bottom: 10px;font-size: 12px">
      <el-breadcrumb-item :to="{ path: '/main' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统管理</el-breadcrumb-item>
      <el-breadcrumb-item>公司企业信息管理</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card class="box-card">
      <el-table
        :data="userList"
        border
        max-height="400"
        style="width: 100%;">
        <el-table-column
          prop="id"
          type="index"
          label="#"
          width="50">
        </el-table-column>

        <el-table-column width="100">
          <template slot-scope="scope">
            <img v-if="scope.row.imgtype=='image/jpeg'"
                 :src="require('../../assets/uploadImgs/'+scope.row.cimg)"
                 width="40" height="40" class="head_pic"/>
            <img v-else-if="scope.row.imgtype=='image/png'"
                 :src="require('../../assets/uploadImgs/'+scope.row.cimg)"
                 width="40" height="40" class="head_pic"/>
          </template>
        </el-table-column>

        <el-table-column
          prop="cname"
          label="企业名称"
          width="180">
        </el-table-column>

        <el-table-column
          prop="cpwd"
          label="密码"
          width="120">
        </el-table-column>
        <el-table-column
          sortable
          prop="ctel"
          label="电话"
          width="100">
        </el-table-column>
        <el-table-column
          prop="cstaffnums"
          label="员工人数"
          width="100">
        </el-table-column>
        <el-table-column
          prop="cmajor"
          label="服务范围"
          width="300">
        </el-table-column>
        <el-table-column
          prop="cattr"
          label="所在地址"
          width="250">
        </el-table-column>
        <el-table-column
          prop="cstatus"
          label="状态"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作" width="250">
          <template slot-scope="scope">
            <el-button type="primary" size="mini" icon="el-icon-edit" @click="userEdit(scope.row)" title="编辑"></el-button>
          </template>
        </el-table-column>
      </el-table>

      <CompanysEdit2 :addOrUpdateVisible="editOrUpdateVisible" @changeShow="showEidtOrUpdate" ref="eidtOrUpdateRef"></CompanysEdit2>
    </el-card>
  </div>

</template>

<script>
  import { findCompanysOneList,findCompanysById,deleteCompanys,passCompanys,nopassCompanys } from '../../api/companys';

  import CompanysEdit2 from './CompanysEdit2';

  export default {
    name: 'Companys2',
    data() {
      return {
        addOrUpdateVisible: false,
        editOrUpdateVisible: false,
        userList: [],
        size: 6,
        total: 100,
        current: 1
      };
    },
    components: {
      CompanysEdit2
    },
    created(){
      this.getUserList();
    },
    methods: {
      onSubmit() {
        console.log('submit!');
      },
      handleSizeChange(val) {
        this.size = val;
        this.getUserList();
      },
      handleCurrentChange(val) {
        this.current = val;
        this.getUserList();
      },
      async getUserList(){
        if(this.$session.get("phone") == null)
          this.$router.push("/login");
        const { data } = await findCompanysOneList(this.$session.get("phone"));
        this.userList = data.data.records;
      },
      show(){
        this.addOrUpdateVisible = true;
      },
       userEdit(row){
        var that = this;
         this.editOrUpdateVisible = true;
        this.$nextTick(() => {
            that.$refs.eidtOrUpdateRef.dataInit(row);
        });
         this.getUserList();
        console.log(this.userEdit);
      },
      showAddOrUpdate(data){
        if(data === 'false'){
          this.addOrUpdateVisible = false;
        }else{
          this.addOrUpdateVisible = true;
        }
        this.getUserList();
      },
      showEidtOrUpdate(data){
        if(data === 'false'){
          this.editOrUpdateVisible = false;
        }else{
          this.editOrUpdateVisible = true;
        }
        this.getUserList();
      }
    }
  };
</script>

